#define LIMIT -999

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

int maximum(int a, int b, int c) {
    int k;
    if (b >= a)
        k = b;
    else
        k = a;

    if (c >= k)
        return c;
    else
        return k;
}

__kernel void nw_kernel1(__global int *referrence,
                         __global int *input_itemsets,
                         __global int *tmp_0,
                         __local int *elem_23,
                         __local int *item_16,
                         int max_cols,
                         int penalty,
                         int blk,
                         int block_width,
                         int worksize,
                         int offset_r,
                         int offset_c) {
    int elem_19 = get_global_id(0) / BLOCK_SIZE;

    if (blk > elem_19 || elem_19 >= block_width) {
        return;
    }

    int item_11 = blk - 1 - elem_19;

    int local_i = get_local_id(0);

    // Load reference block into local memory
    for (int i = local_i; i < BLOCK_SIZE; i += BLOCK_SIZE) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            item_16[i * BLOCK_SIZE + j] = referrence[max_cols * (item_11 * BLOCK_SIZE + i + 1) + elem_19 * BLOCK_SIZE + j + 1];
        }
    }

    // Load input block into local memory (size BLOCK_SIZE+1 x BLOCK_SIZE+1)
    for (int i = local_i; i < BLOCK_SIZE + 1; i += BLOCK_SIZE) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            elem_23[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols * (item_11 * BLOCK_SIZE + i) + elem_19 * BLOCK_SIZE + j];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute DP block
    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            int diag = elem_23[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + item_16[(i - 1) * BLOCK_SIZE + j - 1];
            int left = elem_23[i * (BLOCK_SIZE + 1) + j - 1] - penalty;
            int up = elem_23[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty;

            elem_23[i * (BLOCK_SIZE + 1) + j] = maximum(diag, left, up);
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Write results back to global memory
    for (int i = local_i; i < BLOCK_SIZE; i += BLOCK_SIZE) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (item_11 * BLOCK_SIZE + i + 1) + elem_19 * BLOCK_SIZE + j + 1] = elem_23[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

